import React, { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import axios from 'axios';
import ArtisanCard from '../components/ArtisanCard';

const SearchResults = () => {
    const [artisans, setArtisans] = useState([]);
    const [loading, setLoading] = useState(true);
    const { search } = useLocation();
    const params = new URLSearchParams(search);
    const query = params.get('q');
    const category = params.get('category');

    useEffect(() => {
        setLoading(true);
        axios.get(`http://localhost:5000/api/artisans/search${search}`)
            .then(res => {
                setArtisans(res.data);
                setLoading(false);
            })
            .catch(err => {
                console.error("Erreur lors de la recherche:", err);
                setLoading(false);
            });
            
    }, [search]); 

    if (loading) return <div className="container py-5 text-center">Recherche en cours...</div>;

    return (
        <div className="container py-4">
            <h2 className="mb-4">
                {category ? `Catégorie : ${category}` : `Résultats pour : "${query || ''}"`}
            </h2>

            <div className="row">
                {artisans.length > 0 ? (
                    artisans.map(artisan => (
                        <div className="col-md-4 mb-4" key={artisan.id}>
                            <ArtisanCard artisan={artisan} />
                        </div>
                    ))
                ) : (
                    <div className="alert alert-warning">
                        Aucun artisan ne correspond à cette sélection.
                    </div>
                )}
            </div>
        </div>
    );
};

export default SearchResults;
